What does this program print?

```cpp
#include <iostream>
class Score {
    int m_val;
public:
    Score(int v) : m_val{v} {}
    operator int() const { return m_val * 2; }
};
int main() {
    Score s{7};
    int x = s;
    std::cout << x << '\n';
}
```

