class Positive {
    int m_val;
public:
    Positive(int v) : m_val{v} {}
    operator bool() const { return m_val >= 0; }
};
int main() {
    Positive z{0};
    if (z) std::cout << 1 << '\n';
    else   std::cout << 0 << '\n';
}
