What does this program print?

```cpp
#include <iostream>
class Box {
    int m_items;
public:
    Box(int n) : m_items{n} {}
    explicit operator bool() const { return m_items > 0; }
};
int main() {
    Box empty{0};
    Box full{3};
    std::cout << (full ? "yes" : "no") << '\n';
    std::cout << (empty ? "yes" : "no") << '\n';
}
```
